import { useEffect, useMemo, useRef, useState } from "react"

const STRIKES_WIN = 3
const SERIES_WIN = 2
const LS_NAMES = "strike-zone:names"
const LS_HIST = "strike-zone:history"
const TARGET_MS = 5000

const GAMES = [
  { id: "tap-race", name: "Tap Race", emoji: "👊", type: "sim", rules: "Tap your half of the screen as fast as you can. Most taps when the timer runs out wins the point." },
  { id: "reaction-duel", name: "Reaction Duel", emoji: "⚡", type: "sim", rules: "Wait for green, then tap first. Tap early and you lose the point." },
  { id: "rock-paper-scissors", name: "Rock Paper Scissors", emoji: "✊", type: "pnp", rules: "Pick rock, paper, or scissors, then pass the phone. The second player picks, then both choices are revealed." },
  { id: "stop-the-bar", name: "Stop the Bar", emoji: "🎯", type: "pnp", rules: "Pass the phone. Each player freezes the moving bar. Closest to center wins the point." },
  { id: "color-trap", name: "Color Trap", emoji: "🚦", type: "pnp", rules: "Tap green tiles for +1. Red tiles cost -1. You have 8 seconds. Higher score wins the point." },
  { id: "hold-release", name: "Hold & Release", emoji: "⏱️", type: "pnp", rules: "Hold the button, then release when you think exactly 5 seconds have passed. Closest wins the point." },
  { id: "memory-pattern", name: "Memory Pattern", emoji: "🧠", type: "pnp", rules: "Watch the sequence, then repeat it. Both players get the same pattern. Most correct wins the point." },
  { id: "estimate-time", name: "Estimate Time", emoji: "⌚", type: "pnp", rules: "Tap start, then stop when you think exactly 5 seconds have passed. Closest wins the point." },
]

const MP_COLORS = ["r", "b", "g", "y"]
const MP_LABELS = { r: "🔴", b: "🔵", g: "🟢", y: "🟡" }
const RPS = [
  { id: "rock", label: "Rock", emoji: "✊", beats: "scissors" },
  { id: "paper", label: "Paper", emoji: "✋", beats: "rock" },
  { id: "scissors", label: "Scissors", emoji: "✌️", beats: "paper" },
]
const CONFETTI_COLORS = ["#ff2d6e", "#00e5ff", "#ffd700", "#ff6600", "#cc00ff", "#00ff88"]

function safeParse(value, fallback) { try { return value ? JSON.parse(value) : fallback } catch { return fallback } }
function readStorage(key, fallback) { if (typeof window === "undefined") return fallback; return safeParse(window.localStorage.getItem(key), fallback) }
function writeStorage(key, value) { try { window.localStorage.setItem(key, JSON.stringify(value)) } catch {} }
function formatMs(ms) { return `${(ms / 1000).toFixed(3)}s` }
function diffFromTarget(ms) { const seconds = (ms - TARGET_MS) / 1000; return `${seconds >= 0 ? "+" : ""}${seconds.toFixed(3)}s` }
function chooseLoser(scoreA, scoreB, lowerIsBetter = false) { if (scoreA === scoreB) return Math.random() < 0.5 ? 0 : 1; if (lowerIsBetter) return scoreA < scoreB ? 1 : 0; return scoreA > scoreB ? 1 : 0 }
function pickGame(recent = []) { const excluded = new Set(recent.slice(-2)); const pool = GAMES.filter((game) => !excluded.has(game.id)); const choices = pool.length ? pool : GAMES; return choices[Math.floor(Math.random() * choices.length)] }

function useTimers() {
  const timers = useRef([])
  const addTimeout = (fn, ms) => { const id = window.setTimeout(fn, ms); timers.current.push({ id, type: "timeout" }); return id }
  const addInterval = (fn, ms) => { const id = window.setInterval(fn, ms); timers.current.push({ id, type: "interval" }); return id }
  const clearAll = () => { timers.current.forEach(({ id, type }) => { if (type === "interval") window.clearInterval(id); else window.clearTimeout(id) }); timers.current = [] }
  useEffect(() => clearAll, [])
  return { addTimeout, addInterval, clearAll }
}

